import logging
from datetime import datetime, timezone
from os import environ

from psycopg2 import connect


class RdsDbClient(object):
    # Connects to AWS RDS database, and performs queries
    def __init__(self, db_name=environ.get('RDS_DB_NAME'),
                 db_user=environ.get('RDS_USERNAME'),
                 db_password=environ.get('RDS_PASSWORD'),
                 db_host=environ.get('RDS_HOSTNAME'),
                 db_port=environ.get('RDS_PORT')):
        self._connection = None
        try:
            self._connection = connect(
                database=db_name,
                user=db_user,
                password=db_password,
                host=db_host,
                port=db_port,
            )
        except Exception as err:
            logging.error("Failed to connect to the DB at {}. The error '{}' occurred".format(
                db_name, repr(err)))

        self.farm_id = None
        self.robot_id = None
        self.storage_unit_id = None

    def is_connected(self) -> bool:
        return bool(self._connection)

    def subscription_valid(self, farm_name: str) -> bool:
        # Check account subscription expiry
        query = "SELECT account.subscription_expiry FROM app_storagesite as farm JOIN app_account as account ON farm.account_id = account.id WHERE farm.name = %(farm_name)s"
        query_data = {"farm_name": farm_name}
        result = self._select_query(query, query_data)
        if not result:
            return False
        else:
            expiry = result[0][0]
            cur_datetime = datetime.now(timezone.utc)
            return cur_datetime < expiry

    # Executes SELECT DB query
    def _select_query(self, query, query_data):
        self._connection.autocommit = True
        cursor = self._connection.cursor()
        try:
            cursor.execute(query, query_data)
            return cursor.fetchall()
        except Exception as err:
            logging.error(
                "SELECT query failed: {}\n The error '{}' occurred".format(query, repr(err)))
            return None

    # Executes INSERT DB query
    def user_query(self, query, query_data) -> bool:
        self._connection.autocommit = True
        cursor = self._connection.cursor()
        try:
            cursor.execute(query, query_data)
            return True
        except Exception as err:
            logging.error(
                "User query failed: {}\n The error '{}' occurred".format(query, repr(err)))
            return False

    def check_farm_id(self, farm_name):
        farm_query_str = "SELECT id FROM app_storagesite WHERE name = %(farm)s"
        farm_query_data = {'farm': farm_name}
        farm_query_result = self._select_query(farm_query_str, farm_query_data)

        if not farm_query_result:
            logging.error("Farm {} doesn't exist".format(farm_name))
            return False

        self.farm_id = int(farm_query_result[0][0])
        return True
